+/// Rejects requests whose Content-Length exceeds [`MAX_REQUEST_BODY_BYTES`].
+#[derive(Clone, Default)]
+pub(super) struct BodySizeGuard;
+
+impl Middleware for BodySizeGuard {
+    fn before<'a>(
+        &'a self,
+        _ctx: &'a RequestContext,
+        req: &'a mut Request,
+    ) -> BoxFuture<'a, ControlFlow> {
+        if let Some(cl) = req
+            .headers()
+            .get("content-length")
